mapper.select:
SELECT t1.id, t1.project_id, t1.head_id, t1.contract_name, t1.area, t1.amount, t1.create_time, t1.create_by, t1.update_by, t1.update_time, t2.name as headName, t3.project_name as projectName
FROM sys_contract t1 left join sys_worker_user t2 on t2.id = t1.head_id left join sys_project t3 on t3.project_id = t1.project_id
and t1.project_id = #{sysContractVo.projectId}
and t1.contract_name = #{sysContractVo.contractName}
and t1.create_time BETWEEN #{sysContractVo.createTime} and #{sysContractVo.endTime}
order by t1.create_time desc
